const now = new Date();
const cats = [
  {gem:'face cream moisturizer', kr:'수분크림/페이스크림'},
  {gem:'sunscreen SPF UV protection', kr:'선크림'},
  {gem:'shampoo hair cleansing', kr:'샴푸'},
  {gem:'facial cleanser face wash', kr:'클렌저'},
  {gem:'body lotion body milk', kr:'바디로션'},
  {gem:'toner skin tonic', kr:'토너/스킨'},
  {gem:'lip balm lipstick lip care', kr:'립밤/립스틱'},
  {gem:'foundation BB cream CC cream', kr:'파운데이션'},
  {gem:'eye cream eye serum', kr:'아이크림'},
  {gem:'sheet mask face mask pack', kr:'마스크팩'},
  {gem:'conditioner hair treatment', kr:'컨디셔너'}
];
const regions = ['korea','japan','usa','europe','china'];
const catIdx = Math.floor(Date.now()/1800000) % cats.length;
const regIdx = Math.floor(Date.now()/5400000) % regions.length;
const cat = cats[catIdx];

return [{ json: {
  category: cat.gem,
  kr_name: cat.kr,
  region: regions[regIdx],
  batch_size: 10,
  run_id: 'prod_' + now.toISOString().replace(/[:.]/g,'_'),
  timestamp: now.toISOString()
}}];

const config = $('⚙️ 수집 설정').first().json;

// 기존 수집 제품 제외
let existingProducts = [];
try {
  const dbRows = $('📦 기존 제품 조회').all();
  existingProducts = dbRows
    .map(r => (r.json.brand_name || '') + ' ' + (r.json.product_name || ''))
    .filter(n => n.trim().length > 2);
} catch(e) {}

const excludeList = existingProducts.length > 0
  ? '\n\nEXCLUDE these products (already in DB): ' + existingProducts.slice(0, 50).join(', ')
  : '';

const prompt = `You are a cosmetic product database researcher.
Find 10 REAL commercial cosmetic products.

Category: ${config.category} (${config.kr_name})
Region focus: ${config.region}
${config.region === 'korea' ? 'Focus on K-beauty brands: Sulwhasoo, Laneige, COSRX, Innisfree, Dr.Jart+, Missha, Etude House, ROUND LAB, Anua, Torriden, Beauty of Joseon' : ''}
${config.region === 'japan' ? 'Focus on J-beauty brands: Shiseido, SK-II, Hada Labo, Canmake, MUJI, Kose, Kanebo, DHC' : ''}
${excludeList}

For EACH product provide:
- brand_name: Brand name (English)
- product_name: Full product name (English)
- product_name_local: Local language name (Korean/Japanese/Chinese if applicable)
- full_ingredients: Complete INCI ingredient list (comma separated, MUST be real from actual product label)
- key_ingredients: Top 5 key active ingredients as JSON string
- product_type: cream/serum/lotion/gel/foam/powder/liquid/stick/spray
- target_skin_type: oily/dry/combination/sensitive/normal/all
- ph_range: Estimated pH range (e.g. "5.0-6.0")
- viscosity_type: water-thin/light/medium/thick/paste
- country_of_origin, volume_ml, image_url, brand_website, notable_claims, launch_year
- category: ${config.kr_name}

CRITICAL: Only REAL products with REAL INCI ingredients from actual labels. JSON array only.`;

const geminiBody = JSON.stringify({
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0.4, maxOutputTokens: 16000 }
});

return [{ json: { geminiBody, run_id: config.run_id, category: config.kr_name }}];

const input = $input.first().json;
let products = [];

try {
  let text = '';
  const c = input.candidates;
  if (c && c.length > 0 && c[0].content && c[0].content.parts && c[0].content.parts.length > 0) {
    text = c[0].content.parts[0].text || '';
  }
  if (!text) text = JSON.stringify(input);
  const cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  try { products = JSON.parse(cleaned); } catch(e) {
    const m = cleaned.match(/\[[\s\S]*\]/);
    if (m) { try { products = JSON.parse(m[0]); } catch(e2) {} }
  }
  if (!Array.isArray(products)) products = [products];
} catch(e) {
  return [{ json: { _skip: true, error: 'parse_failed: ' + e.message } }];
}

const result = products.filter(p => p.brand_name && p.product_name).map(p => ({
  json: {
    brand_name: (p.brand_name || '').trim().substring(0, 255),
    product_name: (p.product_name || '').trim().substring(0, 500),
    product_name_local: (p.product_name_local || '').trim().substring(0, 500),
    full_ingredients: (p.full_ingredients || '').trim(),
    key_ingredients: typeof p.key_ingredients === 'string' ? p.key_ingredients : JSON.stringify(p.key_ingredients || []),
    product_type: (p.product_type || '').trim(),
    target_skin_type: (p.target_skin_type || 'all').trim(),
    ph_range: (p.pH_range || p.ph_range || '').trim(),
    viscosity_type: (p.viscosity_type || '').trim(),
    country_of_origin: (p.country_of_origin || '').trim(),
    retail_price_usd: parseFloat(p.retail_price_usd) || null,
    volume_ml: String(p.volume_ml || ''),
    image_url: (p.image_url || '').trim(),
    brand_website: (p.brand_website || '').trim(),
    notable_claims: (p.notable_claims || '').trim(),
    launch_year: parseInt(p.launch_year) || null,
    category: (p.category || '').trim(),
    source: 'gemini_search',
    collected_at: new Date().toISOString()
  }
}));

if (result.length === 0) {
  return [{ json: { _skip: true, reason: 'no_valid_products' } }];
}
return result;

const items = $input.all().filter(i => i.json.id && i.json.full_ingredients);
if (items.length === 0) {
  return [{ json: { _skip: true, reason: 'no_candidates' } }];
}

const products = items.slice(0, 5).map(i => ({
  id: i.json.id,
  name: (i.json.brand_name || '') + ' ' + (i.json.product_name || ''),
  ingredients: (i.json.full_ingredients || '').substring(0, 500)
}));

const prompt = 'You are a cosmetic formulation scientist. Estimate physical properties for these products based on their ingredient lists.\n\nProducts:\n' + JSON.stringify(products, null, 2) + '\n\nFor EACH product estimate:\n1. ph_value: Estimated pH (number, e.g. 5.5)\n2. viscosity_cp: Estimated viscosity in centipoise (number)\n3. specific_gravity: Estimated specific gravity (number)\n4. appearance: Visual description\n5. texture: Texture description\n6. shelf_life_months: Estimated shelf life in months (number)\n7. storage_temp: Storage temperature recommendation\n\nJSON array with product id. No explanation.';

const geminiBody = JSON.stringify({
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0.2, maxOutputTokens: 4096 }
});

return [{ json: { geminiBody } }];

const input = $input.first().json;
if (input._skip) return [{ json: { _skip: true } }];

let results = [];
try {
  let text = '';
  const c = input.candidates;
  if (c && c.length > 0 && c[0].content && c[0].content.parts && c[0].content.parts.length > 0) {
    text = c[0].content.parts[0].text || '';
  }
  if (!text) text = '[]';
  const cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  results = JSON.parse(cleaned);
  if (!Array.isArray(results)) results = [results];
} catch(e) {
  return [{ json: { _skip: true, error: 'property_parse_failed' } }];
}

return results.filter(r => r.id || r.product_id).map(r => ({
  json: {
    product_id: r.id || r.product_id,
    ph_value: parseFloat(r.ph_value) || null,
    viscosity_cp: parseFloat(r.viscosity_cp) || null,
    specific_gravity: parseFloat(r.specific_gravity) || null,
    appearance: (r.appearance || '').trim(),
    texture: (r.texture || '').trim(),
    shelf_life_months: parseInt(r.shelf_life_months) || null,
    storage_temp: (r.storage_temp || '').trim()
  }
}));

// Claude 분석 준비
const timestamp = new Date().toISOString();
const prompt = '최근 수집된 화장품 제품 전성분 검증 및 가이드처방 DB 연계 분석을 3문장으로 요약해줘.';
return [{ json: { claudePrompt: prompt, timestamp } }];

const input = $input.first().json;
const config = $('⚙️ 수집 설정').first().json;
let analysis = {};
try { analysis = JSON.parse(input.stdout || '{}'); } catch(e) {
  analysis = { raw: (input.stdout || input.stderr || '').substring(0, 500) };
}

return [{ json: {
  run_id: config.run_id,
  details: { claude_analysis: analysis, category: config.kr_name, region: config.region },
  report: '✅ 제품 수집 완료',
  timestamp: new Date().toISOString(),
  next_run: new Date(Date.now() + 3*60*60*1000).toISOString()
}}];

const input = $input.first().json;
const items = input.body?.items || [];
if (!items.length) return [{ json: { skip: true } }];

return items.filter(i => i.ENTP_NAME).map(i => ({
  json: {
    company_name: (i.ENTP_NAME || '').trim(),
    business_type: (i.INDUTY || '').trim(),
    representative: (i.BOSS_NAME || '').trim(),
    address: (i.FACTORY_ADDR || '').trim(),
    registration_date: (i.ENTP_PERMIT_DATE || '').trim(),
    source: 'mfds_korea',
    collected_at: new Date().toISOString()
  }
}));
